import 'package:flutter/foundation.dart';

// --- Log Level ---

enum LogLevel {
  verbose,
  debug,
  info,
  warning,
  error,
  fatal,
  none,
}

extension LogLevelExtension on LogLevel {
  String get label => ['VERBOSE', 'DEBUG', 'INFO', 'WARN', 'ERROR', 'FATAL', 'NONE'][index];
  bool operator >=(LogLevel other) => index >= other.index;
}

// --- Sanitizer: Ensures sensitive data NEVER appears in logs ---

class LogSanitizer {
  static const _sensitiveKeys = {
    'password',
    'passwd',
    'pass',
    'secret',
    'token',
    'access_token',
    'refresh_token',
    'id_token',
    'authorization',
    'cookie',
    'set-cookie',
    'api_key',
    'apikey',
    'api-key',
    'credit_card',
    'card_number',
    'cvv',
    'ssn',
    'social_security',
    'pin',
    'otp',
    'totp',
    'private_key',
    'client_secret',
    'x-api-key',
    'x-auth-token',
    'bearer',
  };

  static const _redacted = '[REDACTED]';

  /// Sanitize a map (e.g., headers, body, query params)
  static Map<String, dynamic> sanitizeMap(Map<String, dynamic>? input) {
    if (input == null) return {};
    final sanitized = <String, dynamic>{};
    for (final entry in input.entries) {
      final keyLower = entry.key.toLowerCase();
      if (_sensitiveKeys.any((s) => keyLower.contains(s))) {
        sanitized[entry.key] = _redacted;
      } else if (entry.value is Map<String, dynamic>) {
        sanitized[entry.key] = sanitizeMap(entry.value as Map<String, dynamic>);
      } else if (entry.value is List) {
        sanitized[entry.key] = _sanitizeList(entry.value as List);
      } else {
        sanitized[entry.key] = entry.value;
      }
    }
    return sanitized;
  }

  static List _sanitizeList(List input) {
    return input.map((item) {
      if (item is Map<String, dynamic>) return sanitizeMap(item);
      if (item is List) return _sanitizeList(item);
      return item;
    }).toList();
  }

  /// Sanitize headers specifically (handles Authorization bearer tokens etc.)
  static Map<String, String> sanitizeHeaders(Map<String, String>? headers) {
    if (headers == null) return {};
    final sanitized = <String, String>{};
    for (final entry in headers.entries) {
      final keyLower = entry.key.toLowerCase();
      if (_sensitiveKeys.any((s) => keyLower.contains(s))) {
        // For Authorization, show scheme but redact the token
        if (keyLower == 'authorization' && entry.value.contains(' ')) {
          final scheme = entry.value.split(' ').first;
          sanitized[entry.key] = '$scheme $_redacted';
        } else {
          sanitized[entry.key] = _redacted;
        }
      } else {
        sanitized[entry.key] = entry.value;
      }
    }
    return sanitized;
  }

  /// Sanitize a JSON string body
  static String sanitizeJsonBody(String? body) {
    if (body == null || body.isEmpty) return '';
    try {
      final decoded = jsonDecode(body);
      if (decoded is Map<String, dynamic>) {
        return jsonEncode(sanitizeMap(decoded));
      }
      if (decoded is List) {
        return jsonEncode(_sanitizeList(decoded));
      }
      return body;
    } catch (_) {
      // Not valid JSON; check for sensitive patterns via regex
      return _redactPatternsInString(body);
    }
  }

  static String _redactPatternsInString(String input) {
    var result = input;
    // Redact common token/password patterns
    result = result.replaceAll(
      RegExp(r'(?i)(password|token|secret|api_key|authorization)["\s:=]+["\s]*[^\s"&,}{]+'),
      '\$1=$_redacted',
    );
    return result;
  }

  /// Mask an email for logging: j***@example.com
  static String maskEmail(String? email) {
    if (email == null || !email.contains('@')) return _redacted;
    final parts = email.split('@');
    final local = parts[0];
    final domain = parts[1];
    if (local.length <= 1) return '***@$domain';
    return '${local[0]}***@$domain';
  }

  /// Mask a user ID: show first 4 and last 2 chars
  static String maskUserId(String? userId) {
    if (userId == null || userId.length < 8) return _redacted;
    return '${userId.substring(0, 4)}...${userId.substring(userId.length - 2)}';
  }
}

// --- Log Entry ---

class LogEntry {
  final DateTime timestamp;
  final LogLevel level;
  final String category;
  final String message;
  final Map<String, dynamic>? metadata;
  final String? errorMessage;
  final String? stackTrace;
  final String? correlationId;

  LogEntry({
    required this.level,
    required this.category,
    required this.message,
    this.metadata,
    this.errorMessage,
    this.stackTrace,
    this.correlationId,
  }) : timestamp = DateTime.now().toUtc();

  Map<String, dynamic> toJson() => {
        'timestamp': timestamp.toIso8601String(),
        'level': level.label,
        'category': category,
        'message': message,
        if (metadata != null && metadata!.isNotEmpty) 'metadata': metadata,
        if (errorMessage != null) 'error': errorMessage,
        if (stackTrace != null) 'stackTrace': stackTrace,
        if (correlationId != null) 'correlationId': correlationId,
      };

  @override
  String toString() {
    final buffer = StringBuffer();
    buffer.write('[${timestamp.toIso8601String()}] ');
    buffer.write('[${level.label}] ');
    buffer.write('[$category] ');
    if (correlationId != null) buffer.write('(${correlationId!.substring(0, 8)}) ');
    buffer.write(message);
    if (metadata != null && metadata!.isNotEmpty) {
      buffer.write(' | ${jsonEncode(metadata)}');
    }
    if (errorMessage != null) buffer.write(' | ERROR: $errorMessage');
    return buffer.toString();
  }
}

// --- Log Sink Interface ---

abstract class LogSink {
  Future<void> write(LogEntry entry);
  Future<void> flush();
  Future<void> dispose();
}

// --- Console Sink (debug builds only) ---

class ConsoleSink implements LogSink {
  @override
  Future<void> write(LogEntry entry) async {
    // Only output to console in debug mode
    if (kDebugMode) {
      final output = entry.toString();
      // Use debugPrint for long messages to avoid truncation
      if (output.length > 800) {
        debugPrint(output);
      } else {
        // ignore: avoid_print
        print(output);
      }
    }
  }

  @override
  Future<void> flush() async {}

  @override
  Future<void> dispose() async {}
}

// --- File Sink (for local log storage with rotation) ---

class FileSink implements LogSink {
  final String logDirectory;
  final int maxFileSizeBytes;
  final int maxFileCount;
  IOSink? _currentSink;
  File? _currentFile;
  int _currentSize = 0;

  FileSink({
    required this.logDirectory,
    this.maxFileSizeBytes = 5 * 1024 * 1024, // 5 MB
    this.maxFileCount = 5,
  });

  Future<void> _ensureFile() async {
    if (_currentSink != null) return;
    final dir = Directory(logDirectory);
    if (!await dir.exists()) await dir.create(recursive: true);
    final fileName = 'app_${DateTime.now().toUtc().toIso8601String().replaceAll(':', '-')}.log';
    _currentFile = File('${dir.path}/$fileName');
    _currentSink = _currentFile!.openWrite(mode: FileMode.append);
    _currentSize = await _currentFile!.exists() ? await _currentFile!.length() : 0;
    await _rotateIfNeeded();
  }

  Future<void> _rotateIfNeeded() async {
    if (_currentSize < maxFileSizeBytes) return;
    await _currentSink?.flush();
    await _currentSink?.close();
    _currentSink = null;
    _currentFile = null;
    _currentSize = 0;

    // Clean up old files
    final dir = Directory(logDirectory);
    final files = await dir
        .list()
        .where((e) => e is File && e.path.endsWith('.log'))
        .cast<File>()
        .toList();
    files.sort((a, b) => a.path.compareTo(b.path));
    while (files.length >= maxFileCount) {
      await files.removeAt(0).delete();
    }

    await _ensureFile();
  }

  @override
  Future<void> write(LogEntry entry) async {
    await _ensureFile();
    final line = '${jsonEncode(entry.toJson())}\n';
    _currentSink!.write(line);
    _currentSize += line.length;
    await _rotateIfNeeded();
  }

  @override
  Future<void> flush() async {
    await _currentSink?.flush();
  }

  @override
  Future<void> dispose() async {
    await _currentSink?.flush();
    await _currentSink?.close();
  }
}

// --- Remote Sink (sends to backend monitoring service) ---

class RemoteSink implements LogSink {
  final String endpoint;
  final Duration flushInterval;
  final int batchSize;
  final List<LogEntry> _buffer = [];
  Timer? _flushTimer;
  final HttpClient _client = HttpClient();

  RemoteSink({
    required this.endpoint,
    this.flushInterval = const Duration(seconds: 30),
    this.batchSize = 50,
  }) {
    _flushTimer = Timer.periodic(flushInterval, (_) => flush());
  }

  @override
  Future<void> write(LogEntry entry) async {
    _buffer.add(entry);
    if (_buffer.length >= batchSize) {
      await flush();
    }
  }

  @override
  Future<void> flush() async {
    if (_buffer.isEmpty) return;
    final batch = List<LogEntry>.from(_buffer);
    _buffer.clear();
    try {
      final request = await _client.postUrl(Uri.parse(endpoint));
      request.headers.set('Content-Type', 'application/json');
      request.write(jsonEncode(batch.map((e) => e.toJson()).toList()));
      final response = await request.close();
      await response.drain();
    } catch (e) {
      // Re-buffer on failure (but limit to avoid memory issues)
      if (_buffer.length < batchSize * 3) {
        _buffer.insertAll(0, batch);
      }
    }
  }

  @override
  Future<void> dispose() async {
    _flushTimer?.cancel();
    await flush();
    _client.close();
  }
}

// --- Main Logger ---

class AppLogger {
  static AppLogger? _instance;
  static AppLogger get instance => _instance ??= AppLogger._();

  final List<LogSink> _sinks = [];
  LogLevel _minLevel = kDebugMode ? LogLevel.verbose : LogLevel.info;
  String? _sessionId;
  String? _userId;

  AppLogger._();

  /// Initialize the logger with appropriate sinks and level
  void initialize({
    required LogLevel minLevel,
    required List<LogSink> sinks,
    String? sessionId,
  }) {
    _minLevel = minLevel;
    _sinks.clear();
    _sinks.addAll(sinks);
    _sessionId = sessionId;
  }

  void setUserId(String? userId) {
    // Store masked version only
    _userId = userId != null ? LogSanitizer.maskUserId(userId) : null;
  }

  void setSessionId(String? sessionId) {
    _sessionId = sessionId;
  }

  void _log(
    LogLevel level,
    String category,
    String message, {
    Map<String, dynamic>? metadata,
    Object? error,
    StackTrace? stackTrace,
    String? correlationId,
  }) {
    if (level.index < _minLevel.index) return;

    // Always sanitize metadata before logging
    final sanitizedMetadata = <String, dynamic>{};
    if (metadata != null) {
      sanitizedMetadata.addAll(LogSanitizer.sanitizeMap(metadata));
    }
    if (_sessionId != null) sanitizedMetadata['sessionId'] = _sessionId;
    if (_userId != null) sanitizedMetadata['userId'] = _userId;

    final entry = LogEntry(
      level: level,
      category: category,
      message: message,
      metadata: sanitizedMetadata.isNotEmpty ? sanitizedMetadata : null,
      errorMessage: error?.toString(),
      stackTrace: stackTrace?.toString(),
      correlationId: correlationId,
    );

    for (final sink in _sinks) {
      sink.write(entry);
    }
  }

  void verbose(String category, String message, {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.verbose, category, message, metadata: metadata);

  void debug(String category, String message, {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.debug, category, message, metadata: metadata);

  void info(String category, String message, {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.info, category, message, metadata: metadata);

  void warning(String category, String message,
          {Map<String, dynamic>? metadata, Object? error}) =>
      _log(LogLevel.warning, category, message, metadata: metadata, error: error);

  void error(String category, String message,
          {Map<String, dynamic>? metadata, Object? error, StackTrace? stackTrace}) =>
      _log(LogLevel.error, category, message,
          metadata: metadata, error: error, stackTrace: stackTrace);

  void fatal(String category, String message,
          {Map<String, dynamic>? metadata, Object? error, StackTrace? stackTrace}) =>
      _log(LogLevel.fatal, category, message,
          metadata: metadata, error: error, stackTrace: stackTrace);

  Future<void> flush() async {
    for (final sink in _sinks) {
      await sink.flush();
    }
  }

  Future<void> dispose() async {
    for (final sink in _sinks) {
      await sink.dispose();
    }
    _sinks.clear();
  }
}

// --- HTTP Request/Response Logger ---

class HttpLogger {
  static const _category = 'HTTP';
  final AppLogger _logger;

  HttpLogger({AppLogger? logger}) : _logger = logger ?? AppLogger.instance;

  /// Log an outgoing HTTP request (sanitized)
  void logRequest({
    required String method,
    required String url,
    Map<String, String>? headers,
    dynamic body,
    String? correlationId,
  }) {
    final uri = Uri.parse(url);
    final sanitizedHeaders = LogSanitizer.sanitizeHeaders(headers);
    String? sanitizedBody;
    if (body is String) {
      sanitizedBody = LogSanitizer.sanitizeJsonBody(body);
    } else if (body is Map<String, dynamic>) {
      sanitizedBody = jsonEncode(LogSanitizer.sanitizeMap(body));
    }

    _logger.info(_category, '$method ${uri.path}', metadata: {
      'method': method,
      'url': '${uri.scheme}://${uri.host}${uri.path}',
      // Sanitize query parameters too
      if (uri.queryParameters.isNotEmpty)
        'queryParams': LogSanitizer.sanitizeMap(
          uri.queryParameters.map((k, v) => MapEntry(k, v as dynamic)),
        ),
      'headers': sanitizedHeaders,
      if (sanitizedBody != null) 'bodyPreview': _truncate(sanitizedBody, 500),
      if (correlationId != null) 'correlationId': correlationId,
    });
  }

  /// Log an HTTP response (sanitized)
  void logResponse({
    required String method,
    required String url,
    required int statusCode,
    Map<String, String>? headers,
    String? body,
    Duration? duration,
    String? correlationId,
  }) {
    final uri = Uri.parse(url);
    final level = statusCode >= 500
        ? LogLevel.error
        : statusCode >= 400
            ? LogLevel.warning
            : LogLevel.info;

    final sanitizedHeaders = LogSanitizer.sanitizeHeaders(headers);
    final sanitizedBody = LogSanitizer.sanitizeJsonBody(body);

    _logger._log(level, _category, '$method ${uri.path} → $statusCode', metadata: {
      'method': method,
      'url': '${uri.scheme}://${uri.host}${uri.path}',
      'statusCode': statusCode,
      'headers': sanitizedHeaders,
      if (sanitizedBody.isNotEmpty) 'bodyPreview': _truncate(sanitizedBody, 500),
      if (duration != null) 'durationMs': duration.inMilliseconds,
      if (correlationId != null) 'correlationId': correlationId,
    });
  }

  /// Log HTTP errors
  void logError({
    required String method,
    required String url,
    required Object error,
    StackTrace? stackTrace,
    Duration? duration,
    String? correlationId,
  }) {
    final uri = Uri.parse(url);
    _logger.error(
      _category,
      '$method ${uri.path} FAILED',
      metadata: {
        'method': method,
        'url': '${uri.scheme}://${uri.host}${uri.path}',
        if (duration != null) 'durationMs': duration.inMilliseconds,
        if (correlationId != null) 'correlationId': correlationId,
      },
      error: error,
      stackTrace: stackTrace,
    );
  }

  String _truncate(String s, int maxLength) {
    if (s.length <= maxLength) return s;
    return '${s.substring(0, maxLength)}... [truncated]';
  }
}

// --- Database Operation Logger ---

class DatabaseLogger {
  static const _category = 'DATABASE';
  final AppLogger _logger;

  DatabaseLogger({AppLogger? logger}) : _logger = logger ?? AppLogger.instance;

  void logQuery({
    required String operation,
    required String table,
    Map<String, dynamic>? parameters,
    int? rowsAffected,
    Duration? duration,
  }) {
    _logger.info(_category, '$operation on $table', metadata: {
      'operation': operation,
      'table': table,
      if (parameters != null) 'params': LogSanitizer.sanitizeMap(parameters),
      if (rowsAffected != null) 'rowsAffected': rowsAffected,
      if (duration != null) 'durationMs': duration.inMilliseconds,
    });
  }

  void logError({
    required String operation,
    required String table,
    required Object error,
    StackTrace? stackTrace,
  }) {
    _logger.error(
      _category,
      '$operation on $table FAILED',
      metadata: {'operation': operation, 'table': table},
      error: error,
      stackTrace: stackTrace,
    );
  }

  void logMigration({
    required int fromVersion,
    required int toVersion,
    required bool success,
    Duration? duration,
  }) {
    final level = success ? LogLevel.info : LogLevel.error;
    _logger._log(level, _category, 'Migration v$fromVersion → v$toVersion: ${success ? 'OK' : 'FAILED'}',
        metadata: {
          'fromVersion': fromVersion,
          'toVersion': toVersion,
          'success': success,
          if (duration != null) 'durationMs': duration.inMilliseconds,
        });
  }
}

// --- Authentication Flow Logger ---
// ⚠️ This logger is DELIBERATELY designed to NEVER log credentials or tokens.
// It logs auth events, outcomes, and non-sensitive metadata only.

class AuthLogger {
  static const _category = 'AUTH';
  final AppLogger _logger;

  AuthLogger({AppLogger? logger}) : _logger = logger ?? AppLogger.instance;

  void logLoginAttempt({
    required String method, // e.g., 'email', 'google', 'apple', 'biometric'
    String? email,
  }) {
    _logger.info(_category, 'Login attempt via $method', metadata: {
      'method': method,
      // Only log masked email - NEVER the full email
      if (email != null) 'user': LogSanitizer.maskEmail(email),
    });
  }

  void logLoginSuccess({
    required String method,
    String? userId,
  }) {
    _logger.info(_category, 'Login successful via $method', metadata: {
      'method': method,
      if (userId != null) 'userId': LogSanitizer.maskUserId(userId),
      // NEVER log the token here
    });
  }

  void logLoginFailure({
    required String method,
    required String reason, // e.g., 'invalid_credentials', 'account_locked', 'network_error'
    String? email,
  }) {
    _logger.warning(_category, 'Login failed via $method: $reason', metadata: {
      'method': method,
      'reason': reason,
      if (email != null) 'user': LogSanitizer.maskEmail(email),
      // NEVER log the password or token here
    });
  }

  void logLogout({String? userId, String? reason}) {
    _logger.info(_category, 'User logged out', metadata: {
      if (userId != null) 'userId': LogSanitizer.maskUserId(userId),
      if (reason != null) 'reason': reason,
    });
  }

  void logTokenRefresh({required bool success, String? errorReason}) {
    if (success) {
      _logger.debug(_category, 'Token refreshed successfully');
    } else {
      _logger.warning(_category, 'Token refresh failed', metadata: {
        if (errorReason != null) 'reason': errorReason,
        // NEVER log the old or new token
      });
    }
  }

  void logRegistration({
    required String method,
    required bool success,
    String? email,
    String? errorReason,
  }) {
    final level = success ? LogLevel.info : LogLevel.warning;
    _logger._log(level, _category, 'Registration ${success ? 'successful' : 'failed'} via $method',
        metadata: {
          'method': method,
          'success': success,
          if (email != null) 'user': LogSanitizer.maskEmail(email),
          if (errorReason != null) 'reason': errorReason,
        });
  }

  void logPasswordReset({required bool requested, String? email}) {
    _logger.info(_category, 'Password reset ${requested ? 'requested' : 'completed'}', metadata: {
      if (email != null) 'user': LogSanitizer.maskEmail(email),
    });
  }

  void logMfaChallenge({required String type, required bool success}) {
    _logger.info(_category, 'MFA $type ${success ? 'passed' : 'failed'}', metadata: {
      'mfaType': type,
      'success': success,
      // NEVER log OTP codes
    });
  }
}

