// --- Performance Logger ---

class PerformanceLogger {
  static const _category = 'PERF';
  final AppLogger _logger;
  final Map<String, DateTime> _timers = {};

  PerformanceLogger({AppLogger? logger}) : _logger = logger ?? AppLogger.instance;

  void startTimer(String name) {
    _timers[name] = DateTime.now();
  }

  void endTimer(String name, {Map<String, dynamic>? metadata}) {
    final start = _timers.remove(name);
    if (start == null) return;
    final duration = DateTime.now().difference(start);
    _logger.info(_category, '$name completed', metadata: {
      'operation': name,
      'durationMs': duration.inMilliseconds,
      if (metadata != null) ...LogSanitizer.sanitizeMap(metadata),
    });
  }

  void logFrameDrop({required int droppedFrames, required Duration duration}) {
    if (droppedFrames > 3) {
      _logger.warning(_category, 'Frame drops detected', metadata: {
        'droppedFrames': droppedFrames,
        'durationMs': duration.inMilliseconds,
      });
    }
  }

  void logMemoryWarning({int? usedMb, int? totalMb}) {
    _logger.warning(_category, 'Memory pressure', metadata: {
      if (usedMb != null) 'usedMb': usedMb,
      if (totalMb != null) 'totalMb': totalMb,
    });
  }

  void logAppLifecycle(String state) {
    _logger.info(_category, 'App lifecycle: $state', metadata: {'state': state});
  }
}

// --- App Health Monitor ---

class AppHealthMonitor {
  final AppLogger _logger;
  Timer? _heartbeatTimer;

  AppHealthMonitor({AppLogger? logger}) : _logger = logger ?? AppLogger.instance;

  void startHeartbeat({Duration interval = const Duration(minutes: 5)}) {
    _heartbeatTimer?.cancel();
    _heartbeatTimer = Timer.periodic(interval, (_) => _sendHeartbeat());
  }

  void _sendHeartbeat() {
    _logger.info('HEALTH', 'Heartbeat', metadata: {
      'uptime': DateTime.now().toUtc().toIso8601String(),
    });
  }

  void logCrash({
    required Object error,
    required StackTrace stackTrace,
    String? context,
  }) {
    _logger.fatal(
      'CRASH',
      context ?? 'Unhandled exception',
      error: error,
      stackTrace: stackTrace,
    );
  }

  void stop() {
    _heartbeatTimer?.cancel();
  }
}

// --- Facade: Single entry point for all loggers ---

class ProductionLogger {
  late final AppLogger app;
  late final HttpLogger http;
  late final DatabaseLogger database;
  late final AuthLogger auth;
  late final InteractionLogger interaction;
  late final PerformanceLogger performance;
  late final AppHealthMonitor health;

  static ProductionLogger? _instance;
  static ProductionLogger get instance => _instance ??= ProductionLogger._();

  ProductionLogger._() {
    app = AppLogger.instance;
    http = HttpLogger();
    database = DatabaseLogger();
    auth = AuthLogger();
    interaction = InteractionLogger();
    performance = PerformanceLogger();
    health = AppHealthMonitor();
  }

  /// Initialize with production-safe defaults
  Future<void> initialize({
    String? logDirectory,
    String? remoteEndpoint,
    String? sessionId,
  }) async {
    final sinks = <LogSink>[
      ConsoleSink(), // Only outputs in debug mode
    ];

    if (logDirectory != null) {
      sinks.add(FileSink(logDirectory: logDirectory));
    }

    if (remoteEndpoint != null) {
      sinks.add(RemoteSink(endpoint: remoteEndpoint));
    }

    app.initialize(
      // In production, log INFO and above. In debug, log everything.
      minLevel: kDebugMode ? LogLevel.verbose : LogLevel.info,
      sinks: sinks,
      sessionId: sessionId,
    );

    health.startHeartbeat();

    app.info('SYSTEM', 'Logger initialized', metadata: {
      'environment': kDebugMode ? 'debug' : 'production',
      'sinksCount': sinks.length,
    });
  }

  /// Set up global error handling
  void setupGlobalErrorHandling() {
    FlutterError.onError = (details) {
      health.logCrash(
        error: details.exception,
        stackTrace: details.stack ?? StackTrace.current,
        context: details.context?.toString(),
      );
    };
  }

  Future<void> dispose() async {
    health.stop();
    await app.flush();
    await app.dispose();
  }
}

// --- Usage Example ---

void main() async {
  final logger = ProductionLogger.instance;

  await logger.initialize(
    logDirectory: '/tmp/app_logs',
    remoteEndpoint: 'https://logging.example.com/ingest',
    sessionId: 'sess_abc123def456',
  );

  logger.setupGlobalErrorHandling();

  // HTTP logging - all sensitive data is automatically sanitized
  logger.http.logRequest(
    method: 'POST',
    url: 'https://api.example.com/auth/login',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer eyJhbGciOiJSUzI1NiIsInR5cCI6IkpXVCJ9...',
    },
    body: {
      'email': 'user@example.com',
      'password': 'supersecret123', // This will be logged as [REDACTED]
    },
  );

  logger.http.logResponse(
    method: 'POST',
    url: 'https://api.example.com/auth/login',
    statusCode: 200,
    headers: {
      'Set-Cookie': 'session=abc123', // This will be logged as [REDACTED]
    },
    body: jsonEncode({
      'access_token': 'eyJhbGci...', // This will be logged as [REDACTED]
      'user': {'id': 'usr_12345678', 'name': 'John'},
    }),
    duration: const Duration(milliseconds: 342),
  );

  // Auth logging - designed to be safe by API design
  logger.auth.logLoginAttempt(
    method: 'email',
    email: 'john.doe@example.com', // Logged as j***@example.com
  );

  logger.auth.logLoginSuccess(
    method: 'email',
    userId: 'usr_a1b2c3d4e5f6', // Logged as usr_...f6
  );

  // Database logging
  logger.database.logQuery(
    operation: 'SELECT',
    table: 'users',
    parameters: {'id': 'usr_123', 'api_key': 'should_be_redacted'},
    rowsAffected: 1,
    duration: const Duration(milliseconds: 12),
  );

  // UI interaction logging
  logger.interaction.logScreenView('HomeScreen');
  logger.interaction.logButtonTap('add_to_cart', screen: 'ProductDetail');

  // Performance
  logger.performance.startTimer('data_sync');
  await Future.delayed(const Duration(seconds: 1));
  logger.performance.endTimer('data_sync');

  // Cleanup
  await logger.dispose();
}